from pydantic_ai import Agent
from vex import ResultValidator

hr_bias_guard = ResultValidator(
    policy='hr-recruitment',
    rules={
        'no_protected_proxies': 'Reject outputs referencing age, ethnicity, gender proxies',
        'score_fairness': 'Flag if scores correlate >0.7 with name/ethnicity signals'
    }
)

resume_screener = Agent(
    'Resume Screener',
    result_validator=hr_bias_guard,
    model='gpt-4o'
)

result = resume_screener.run('Score this resume: [resume text]')
if result.validated:
    print('Safe to proceed:', result.score)
else:
    print('Blocked:', result.violations)

from vex import VexClient

client = VexClient(api_key='your-vex-key')

@client.policy('hr-recruitment')
def validate_hiring_decision(output: dict) -> bool:
    # Check for disparate impact
    if 'score' in output and output['score'] < 0.7:
        if any(proxy in str(output) for proxy in ['age', 'ethnicity', 'gender']):
            client.record_violation(
                decision_id='cand_123',
                violation_type='protected_proxy',
                metadata={'candidate_id': 'cand_123', 'score': output['score']}
            )
            return False
    return True

# Usage in Pydantic AI agent
agent.result_validator = validate_hiring_decision
